import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.BEgbRHOA.js";const p=JSON.parse('{"title":"Заказы и отчёты","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-admin/orders.md","filePath":"guide/xcourier-admin/orders.md","lastUpdated":1775746985000}'),t={name:"guide/xcourier-admin/orders.md"};function o(d,a,h,n,u,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="заказы-и-отчеты" tabindex="-1">Заказы и отчёты <a class="header-anchor" href="#заказы-и-отчеты" aria-label="Permalink to &quot;Заказы и отчёты&quot;">​</a></h1><h2 id="просмотр-заказов" tabindex="-1">Просмотр заказов <a class="header-anchor" href="#просмотр-заказов" aria-label="Permalink to &quot;Просмотр заказов&quot;">​</a></h2><p>Администратор видит заказы по всем магазинам платформы. Заказы можно фильтровать:</p><ul><li>По статусу (Создан, Собирается, В пути, Завершен, Отменен)</li><li>По магазину</li></ul><p>Каждая карточка заказа содержит: номер, статус, имя клиента, магазин, сумму и дату.</p><h2 id="детали-заказа" tabindex="-1">Детали заказа <a class="header-anchor" href="#детали-заказа" aria-label="Permalink to &quot;Детали заказа&quot;">​</a></h2><p>На странице деталей доступна полная информация:</p><ul><li>Данные клиента (имя, телефон, пол, адрес)</li><li>Магазин и его адрес</li><li>Список товаров с количеством и ценами</li><li>Способ оплаты</li><li>Суммы: товары, доставка, итого</li></ul><h2 id="аналитические-отчеты" tabindex="-1">Аналитические отчёты <a class="header-anchor" href="#аналитические-отчеты" aria-label="Permalink to &quot;Аналитические отчёты&quot;">​</a></h2><p>Отдельный экран отчётов по заказам с гибкой фильтрацией:</p><h3 id="периоды" tabindex="-1">Периоды <a class="header-anchor" href="#периоды" aria-label="Permalink to &quot;Периоды&quot;">​</a></h3><ul><li>Сегодня</li><li>7 дней</li><li>30 дней</li><li>Этот месяц</li><li>Произвольный период</li></ul><h3 id="фильтр-по-магазину" tabindex="-1">Фильтр по магазину <a class="header-anchor" href="#фильтр-по-магазину" aria-label="Permalink to &quot;Фильтр по магазину&quot;">​</a></h3><p>Отчёт можно построить по конкретному магазину или по всем сразу.</p><h3 id="метрики" tabindex="-1">Метрики <a class="header-anchor" href="#метрики" aria-label="Permalink to &quot;Метрики&quot;">​</a></h3><ul><li>Общее количество заказов</li><li>Разбивка по статусам (создан, собирается, в пути, завершён, отменён)</li><li>Общая сумма заказов</li><li>Средний чек</li><li>Сумма доставок</li></ul><h3 id="разбивка-по-магазинам" tabindex="-1">Разбивка по магазинам <a class="header-anchor" href="#разбивка-по-магазинам" aria-label="Permalink to &quot;Разбивка по магазинам&quot;">​</a></h3><p>Для каждого магазина:</p><ul><li>Количество заказов (всего, завершённых, отменённых)</li><li>Сумма заказов</li></ul><h3 id="разбивка-по-способам-оплаты" tabindex="-1">Разбивка по способам оплаты <a class="header-anchor" href="#разбивка-по-способам-оплаты" aria-label="Permalink to &quot;Разбивка по способам оплаты&quot;">​</a></h3><p>Для каждого способа оплаты:</p><ul><li>Количество заказов</li><li>Сумма</li></ul>',22)])])}const m=l(t,[["render",o]]);export{p as __pageData,m as default};
